import React, { useEffect, useState } from "react";
import { Link, useLocation } from "react-router-dom";
//hook
import useReq from "../../../hooks/useReq";
//spinner
import Spinner from "../../../components/Spinner";
import { toast, ToastContainer } from "react-toastify";
import { date } from "yup";
import "../Order.css";
function OrderBasicInfo() {
  const [order, setOrder] = useState(null);
  const [uorder, setUOrder] = useState(null);
  const [buyer, setBuyer] = useState(null);
  const [seller, setSelelr] = useState(null);
  const [driver, setDriver] = useState(null);
  const [status, setStatus] = useState(false);
  var data;

  const location = useLocation();
  const { sendRequest } = useReq();
  useEffect(() => {
    const orderId = location.pathname.split("/")[3];
    console.log("order id", orderId);
    sendRequest(`admin/order/${orderId}`, "GET", null, onResponse);
  }, [location]);

  const onResponse = (err, res) => {
    console.log("in");
    if (err) {
      console.log(err);
      return;
    }
    data = res.data.data.order;
    console.log("data", data);

    setOrder(data);
    console.log("orderee", order);
    setBuyer(res.data.data.buyer);
    console.log("buyers", buyer);
    setSelelr(res.data.data.seller);
    setDriver(res.data.data.driver);
    console.log(seller);
  };
  useEffect(() => {
    setOrder(data);
    console.log("orderin", order);
  }, [data]);
  const updateStatus = (status) => {
    const driverId = location.pathname.split("/")[3];
    sendRequest(
      `admin/user/update-status/${driverId}`,
      "PUT",
      { status: status },
      updateStatusResponse
    );
  };

  const updateStatusResponse = (err, res) => {
    if (res && res.data.statusCode === 200) {
      console.log(res);
      driver.status = res.data.data.status;
      toast("Driver status has been updated");
    }
    setStatus(false);
  };

  return (
    <main className="main-content p-5" role="main">
      <div className="row seller-container">
        <div className="col-lg-6">
          <h2>Buyer Details</h2>
          <div className="card mb-5">
            <div className="card-body">
              {buyer ? (
                <div className="row personal-info">
                  <div className="col-lg-4 col-sm-6">
                    <img
                      src={
                        buyer?.photo_url
                          ? buyer?.photo_url
                          : "https://www.gravatar.com/avatar/205e460b479e2e5b48aec07710c08d50"
                      }
                      className="dp"
                      alt="Logo"
                    />
                  </div>
                  <div className="col-lg-8 col-sm-6 ">
                    <div className="row">
                      <div className="col-lg-2"></div>
                      <div className="col-sm-3 col-lg-6">
                        <b> {buyer.name} </b>
                      </div>
                    </div>
                    <div className="row ">
                      <div className="col-lg-2"></div>
                      <div className="col-sm-5 col-lg-5">
                        <i className="batch-icon batch-icon-user-alt-add"></i>{" "}
                        Reviews (215)
                      </div>
                      <div className="col-sm-5 col-lg-5">
                        <span className="text-warning ">
                          {" "}
                          <i className="batch-icon batch-icon-star-alt"></i>
                          <i className="batch-icon batch-icon-star-alt"></i>
                          <i className="batch-icon batch-icon-star-alt"></i>
                          <i className="batch-icon batch-icon-star-alt"></i>
                          <i className="batch-icon batch-icon-star-alt"></i>
                        </span>
                      </div>
                    </div>
                    <div className="row">
                      <div className="col-lg-2"></div>
                      <div className="col-sm-5 col-lg-5">
                        <b>Email:</b>
                      </div>
                      <div
                        className="col-sm-7 col-lg-5"
                        style={{ fontSize: 9 }}
                      >
                        {buyer.email}
                      </div>
                    </div>
                    <div className="row">
                      <div className="col-lg-2"></div>
                      <div className="col-sm-5 col-lg-5">
                        <b>Contact:</b>
                      </div>
                      <div
                        className="col-sm-7 col-lg-5"
                        style={{ fontSize: 9 }}
                      >
                        {buyer.phone_no !== "+undefined"
                          ? buyer.phone_no
                          : "NA"}
                      </div>
                    </div>

                    <div className="row">
                      <div className="col-lg-2"></div>
                      <div className="col-sm-5 col-lg-5">
                        <b>Status:</b>
                      </div>
                      <div className="col-sm-7 col-lg-5">
                        {
                          <span>
                            {buyer.status === "active" && (
                              <span class="badge badge-success">Active</span>
                            )}
                            {buyer.status === "inactive" && (
                              <span class="badge badge-secondary">
                                Inactive
                              </span>
                            )}
                            {buyer.status === "blocked" && (
                              <span class="badge badge-danger">Blocked</span>
                            )}
                            {buyer.status === "pending" && (
                              <span class="badge badge-primary">Pending</span>
                            )}
                          </span>
                        }
                      </div>
                    </div>
                  </div>
                </div>
              ) : (
                <Spinner />
              )}
            </div>
          </div>
        </div>

        <div className="col-lg-6">
          <h2>Seller Details</h2>
          {seller ? (
            <div className="card mb-5">
              <div className="card-body">
                {seller ? (
                  <div className="row personal-info">
                    <div className="col-lg-4 col-sm-6">
                      <img
                        src={
                          seller?.photo_url
                            ? seller?.photo_url
